#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_SIZE 100005

int main() {
    int N, M;
    scanf("%d", &N);
    int* familySizes = (int*)malloc(N * sizeof(int));
    int* familyCounts = (int*)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d %d", &familySizes[i], &familyCounts[i]);
    }
    scanf("%d", &M);
    for (int i = 0; i < M; i++) {
        char queryType;
        int value;
        scanf(" %c %d", &queryType, &value);
        if (queryType == '+') {
            // Add family
            int index = -1;
            for (int j = 0; j < N; j++) {
                if (familySizes[j] == value) {
                    index = j;
                    break;
                }
            }
            if (index == -1) {
                familySizes[N] = value;
                familyCounts[N] = 1;
                N++;
            } else {
                familyCounts[index]++;
            }
        } else if (queryType == '-') {
            // Remove family
            int index = -1;
            for (int j = 0; j < N; j++) {
                if (familySizes[j] == value) {
                    index = j;
                    break;
                }
            }
            if (index != -1) {
                familyCounts[index]--;
                if (familyCounts[index] == 0) {
                    // Remove family size
                    for (int j = index; j < N - 1; j++) {
                        familySizes[j] = familySizes[j + 1];
                        familyCounts[j] = familyCounts[j + 1];
                    }
                    N--;
                }
            }
        } else if (queryType == '?') {
            // Calculate bananas
            int totalBananas = 0;
            for (int j = 0; j < N; j++) {
                totalBananas += (value % familySizes[j]) * familyCounts[j];
            }
            printf("%d\n", totalBananas);
        }
    }
    free(familySizes);
    free(familyCounts);
    return 0;
}

