    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int[] familySizes = new int[N];
        int[] familyCounts = new int[N];
        for (int i = 0; i < N; i++) {
            familySizes[i] = scanner.nextInt();
            familyCounts[i] = scanner.nextInt();
        }
        int M = scanner.nextInt();
        for (int i = 0; i < M; i++) {
            char queryType = scanner.next().charAt(0);
            int value = scanner.nextInt();
            if (queryType == '+') {
                // Add family
                boolean found = false;
                for (int j = 0; j < N; j++) {
                    if (familySizes[j] == value) {
                        familyCounts[j]++;
                        found = true;
                        break;
                    }
                }
                if (!found) {
                    int[] newFamilySizes = new int[N + 1];
                    int[] newFamilyCounts = new int[N + 1];
                    System.arraycopy(familySizes, 0, newFamilySizes, 0, N);
                    System.arraycopy(familyCounts, 0, newFamilyCounts, 0, N);
                    newFamilySizes[N] = value;
                    newFamilyCounts[N] = 1;
                    familySizes = newFamilySizes;
                    familyCounts = newFamilyCounts;
                    N++;
                }
            } else if (queryType == '-') {
                // Remove family
                for (int j = 0; j < N; j++) {
                    if (familySizes[j] == value) {
                        familyCounts[j]--;
                        if (familyCounts[j] == 0) {
                            // Remove family size
                            int[] newFamilySizes = new int[N - 1];
                            int[] newFamilyCounts = new int[N - 1];
                            System.arraycopy(familySizes, 0, newFamilySizes, 0, j);
                            System.arraycopy(familyCounts, 0, newFamilyCounts, 0, j);
                            System.arraycopy(familySizes, j + 1, newFamilySizes, j, N - j - 1);
                            System.arraycopy(familyCounts, j + 1, newFamilyCounts, j, N - j - 1);
                            familySizes = newFamilySizes;
                            familyCounts = newFamilyCounts;
                            N--;
                        }
                        break;
                    }
                }
            } else if (queryType == '?') {
                // Calculate bananas
                int totalBananas = 0;
                for (int j = 0; j < N; j++) {
                    totalBananas += (value % familySizes[j]) * familyCounts[j];
                }
                System.out.println(totalBananas);
            }
        }
    }
}

